import{_ as a,o as t,c as b,j as r,a as n,a1 as s}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"猎手之枪","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/猎手之枪.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/猎手之枪.md"}'),o={name:"4.资源分区/7.物品与装备/2.武器/远程武器/1.D级/猎手之枪.md"};function p(d,e,l,_,i,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"猎手之枪",tabindex:"-1"},[n("猎手之枪 "),r("a",{class:"header-anchor",href:"#猎手之枪","aria-label":'Permalink to "猎手之枪"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001F")])])],-1),s('<h1 id="猎手之枪-1" tabindex="-1">猎手之枪 <a class="header-anchor" href="#猎手之枪-1" aria-label="Permalink to &quot;猎手之枪&quot;">​</a></h1><p>猎手之枪<br> D+1000<br> “不要掺杂任何多余思想。”<br> “天平之上不容杂草滋长。”<br> “务必保证一切精准测量。”<br> “沐浴阳光不容任何遮挡。”<br> 武器采用基础远程武器中的狙击枪模板，具有全部相关特性，在其基础上提升3L武器伤害，高速额外增加1点。</p><p>这把狙击枪，通体斑驳而手感粗糙，若是仔细观察会发现枪身整体由呈深褐色，如一根树木削刻而成，但重量相较于正常枪械也不显轻松。<br> 也许正如猎手所言，公正的代价是如此沉重。</p><p>精准测量：本武器的装弹数不视为6+1，而是1，但只需要装填一次子弹就可以进行六次射击，在第七次射击时必定命中自己，自身在这次攻击中不允许留手，也不能使用任何降低攻击DP的能力。<br> 持有者可以通过重新装填来刷新次数，规避第七次射击。<br> 这意味着即使拥有无限子弹或其他类似能力，也仍然需要进行装填。</p><p>树荫之下：使用本武器时，必须以迅捷动作上膛，移动动作祈祷后才能使用标准动作攻击，这次攻击中附带4点神圣加值。<br> 持有者视为具有D级特异本质的反侦查能力，且攻击时针对的目标必须没有发觉自身，即反侦查生效才能进行攻击并享受对应的好处。<br> 否则，本特性提供加值将暂时失效，武器本身改为标准动作进行普通攻击，直到重新掩蔽起来为止。</p><p>附录1：<br> 仰望眼前的苍天大树，每片叶子都被写满了规则。<br> 猎手自觉的躲在荫庇处。<br> 他对照树冠的纹路，翻阅字典，寻找着子弹塞入枪膛。<br> 猎手虔诚的向神祈祷。<br> 【祈祷神告诉他，子弹的踪迹是否笔直】<br> 【祈祷神指引他，瞄准的目标是否丢失】<br> 【祈祷神宽恕他，伏击在暗处过了几时】</p><p>附录2：<br> 可是，真的是这样吗？<br> 叶片落在每个人的身上，绝非历史的一粒沙。<br> 字典有千斤重，每一页都用尽全力。<br> 每一朵纹路，都史无前例。<br> 在躲进树荫之时，他已经手染肮脏。<br> 说完借口，又何必感伤。<br> 枪是猎手，猎手也是一杆枪。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=a(o,[["render",p]]);export{f as __pageData,m as default};
